import { createApp } from 'vue'

createApp({
  data() {
    return {
      products: [],
    }
  },
  methods: {
    getProducts() {
      axios.get('/products')
        .then((response) => {
          this.products = response.data;
        });
    },
  },
  // mounted
  created() {
    getProducts();
  },
}).mount('#app');

